import{_ as a}from"./chunks/文件受限图.DsG20F9s.js";import{_ as i,o as n,c as t,a2 as l}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"Image Moderation và Access Mode","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/Safety/image-moderation-and-access-mode.md","filePath":"vi-VN/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),o={name:"vi-VN/Safety/image-moderation-and-access-mode.md"};function h(r,e,d,c,s,m){return n(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="image-moderation-va-access-mode" tabindex="-1">Image Moderation và Access Mode <a class="header-anchor" href="#image-moderation-va-access-mode" aria-label="Permalink to &quot;Image Moderation và Access Mode&quot;">​</a></h1><p>Image moderation gán age rating cho uploaded images. Access mode kiểm soát ratings nào được hiển thị qua public access.</p><p>Điều này ảnh hưởng đến public gallery, public file URLs và random image API. Nó không hạn chế admin panel. Administrators vẫn có thể xem và manage tất cả files.</p><h2 id="cau-hinh-o-đau" tabindex="-1">Cấu hình ở đâu <a class="header-anchor" href="#cau-hinh-o-đau" aria-label="Permalink to &quot;Cấu hình ở đâu&quot;">​</a></h2><p>Mở admin panel, rồi vào:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; Image Moderation</span></span></code></pre></div><p>Các settings chính:</p><ul><li>Access mode</li><li>Enable moderation</li><li>Moderation provider</li></ul><h2 id="access-mode-lam-gi" tabindex="-1">Access Mode làm gì <a class="header-anchor" href="#access-mode-lam-gi" aria-label="Permalink to &quot;Access Mode làm gì&quot;">​</a></h2><p>Access mode quyết định age ratings nào có thể hiển thị public.</p><p>Current modes:</p><table tabindex="0"><thead><tr><th>Access Mode</th><th>Publicly Visible Ratings</th></tr></thead><tbody><tr><td>Adult mode</td><td>General, R12, R16, R18</td></tr><tr><td>Youth mode</td><td>General, R12, R16</td></tr><tr><td>Teen mode</td><td>General, R12</td></tr><tr><td>Child mode</td><td>Chỉ General</td></tr></tbody></table><p>Default là Adult mode.</p><p>Với private sites hoặc sites có mature content, Adult mode có thể phù hợp. Nếu muốn public gallery thận trọng hơn, chọn Youth, Teen hoặc Child mode.</p><h2 id="enable-moderation-lam-gi" tabindex="-1">Enable Moderation làm gì <a class="header-anchor" href="#enable-moderation-lam-gi" aria-label="Permalink to &quot;Enable Moderation làm gì&quot;">​</a></h2><p>Khi moderation được bật, ImgBed gọi selected moderation provider trong lúc upload và save age rating được phát hiện.</p><p>Ratings chính:</p><table tabindex="0"><thead><tr><th>Rating</th><th>Meaning</th></tr></thead><tbody><tr><td>General</td><td>Safe public content</td></tr><tr><td>R12</td><td>Content hơi nhạy cảm</td></tr><tr><td>R16</td><td>Content nhạy cảm mức vừa</td></tr><tr><td>R18</td><td>Adult content</td></tr></tbody></table><p>Moderation result được dùng khi quyết định public access.</p><p>Nếu moderation không bật, hoặc old files chưa có rating, các files đó được xem là unrated. Unrated files không tự động bị xóa khỏi public gallery hoặc random image API chỉ vì chưa có rating.</p><h2 id="chon-moderation-provider" tabindex="-1">Chọn Moderation Provider <a class="header-anchor" href="#chon-moderation-provider" aria-label="Permalink to &quot;Chọn Moderation Provider&quot;">​</a></h2><p>Available providers gồm:</p><ul><li>moderatecontent.com</li><li>nsfwjs</li><li>Sightengine</li></ul><p>Mỗi provider có yêu cầu khác nhau:</p><ul><li>moderatecontent.com thường cần API Key.</li><li>nsfwjs thường cần API endpoint URL.</li><li>Sightengine cần API user và API secret.</li></ul><p>Chọn theo account, availability và detection quality của bạn. Miễn là moderation được bật và cấu hình đúng, ImgBed sẽ cố ghi image rating trong lúc upload.</p><h2 id="anh-huong-đen-public-gallery" tabindex="-1">Ảnh hưởng đến Public Gallery <a class="header-anchor" href="#anh-huong-đen-public-gallery" aria-label="Permalink to &quot;Ảnh hưởng đến Public Gallery&quot;">​</a></h2><p>Public gallery filter files theo access mode.</p><p>Ví dụ:</p><ul><li>Adult mode: R18 images có thể xuất hiện.</li><li>Youth mode: R18 images bị ẩn.</li><li>Teen mode: R16 và R18 images bị ẩn.</li><li>Child mode: chỉ General images được hiển thị.</li></ul><p>Điều này chỉ ảnh hưởng normal public access. Admin panel vẫn hiển thị tất cả files.</p><h2 id="anh-huong-đen-public-file-urls" tabindex="-1">Ảnh hưởng đến Public File URLs <a class="header-anchor" href="#anh-huong-đen-public-file-urls" aria-label="Permalink to &quot;Ảnh hưởng đến Public File URLs&quot;">​</a></h2><p>Public file URLs là direct image links mà visitors mở.</p><p>Nếu file rating được current access mode cho phép, ImgBed trả original image.</p><p>Nếu rating cao hơn allowed level, normal public access không trả original image. Thay vào đó, ImgBed trả configured blocked result hoặc blocked fallback image.</p><p>Ví dụ:</p><ul><li>Current mode là Child mode.</li><li>Một image được rating R18.</li><li>Visitor mở public URL trực tiếp.</li><li>ImgBed không trả R18 original image cho visitor đó.</li></ul><p><img src="'+a+'" alt="Restricted file image" loading="lazy"></p><p>Administrators xem files trong admin panel không bị restriction này ảnh hưởng.</p><h2 id="anh-huong-đen-random-image-api" tabindex="-1">Ảnh hưởng đến Random Image API <a class="header-anchor" href="#anh-huong-đen-random-image-api" aria-label="Permalink to &quot;Ảnh hưởng đến Random Image API&quot;">​</a></h2><p>Random image API cũng filter candidate pool theo access mode.</p><p>Ở Child mode, random images chỉ được chọn từ General-rated files.</p><p>Ở Youth mode, random images có thể đến từ General, R12 và R16 files, nhưng không từ R18 files.</p><p>Điều này ngăn random image API bypass public gallery restrictions.</p><h2 id="quan-he-voi-list-rules" tabindex="-1">Quan hệ với List Rules <a class="header-anchor" href="#quan-he-voi-list-rules" aria-label="Permalink to &quot;Quan hệ với List Rules&quot;">​</a></h2><p>Access mode không phải public access rule duy nhất. Nó hoạt động cùng allow/block list rules.</p><p>Hiểu đơn giản:</p><ul><li>Allowlisted content được ưu tiên public.</li><li>Blocklisted content không thể được regular visitors xem trực tiếp.</li><li>Content không nằm trong list nào sẽ được check tiếp theo access mode.</li></ul><p>Nếu một image bị restrict bởi cả age rating và list rules, regular visitors vẫn không thể xem original file trực tiếp.</p><h2 id="recommended-settings" tabindex="-1">Recommended Settings <a class="header-anchor" href="#recommended-settings" aria-label="Permalink to &quot;Recommended Settings&quot;">​</a></h2><p>Với public sites:</p><ul><li>Enable moderation.</li><li>Chọn access mode phù hợp với audience của site.</li><li>Dùng Child mode hoặc Teen mode cho visitors mọi lứa tuổi.</li><li>Tránh Adult mode nếu không muốn mature content hiển thị public.</li><li>Review file ratings trong admin panel và adjust manually khi cần.</li></ul><p>Với private hoặc personal sites:</p><ul><li>Adult mode thường ổn.</li><li>Enable moderation nếu hữu ích.</li><li>Review và adjust ratings trong admin panel khi cần.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="files-co-bien-mat-khoi-admin-panel-sau-khi-đoi-access-mode-khong" tabindex="-1">Files có biến mất khỏi Admin Panel sau khi đổi Access Mode không? <a class="header-anchor" href="#files-co-bien-mat-khoi-admin-panel-sau-khi-đoi-access-mode-khong" aria-label="Permalink to &quot;Files có biến mất khỏi Admin Panel sau khi đổi Access Mode không?&quot;">​</a></h3><p>Không.</p><p>Access mode chỉ ảnh hưởng normal public access. Không ảnh hưởng admin panel.</p><h3 id="vi-sao-public-gallery-hien-thi-it-images-hon-sau-khi-chuyen-sang-child-mode" tabindex="-1">Vì sao Public Gallery hiển thị ít Images hơn sau khi chuyển sang Child Mode? <a class="header-anchor" href="#vi-sao-public-gallery-hien-thi-it-images-hon-sau-khi-chuyen-sang-child-mode" aria-label="Permalink to &quot;Vì sao Public Gallery hiển thị ít Images hơn sau khi chuyển sang Child Mode?&quot;">​</a></h3><p>Child mode chỉ cho phép General-rated files hiển thị public. R12, R16 và R18 files bị filter ra.</p><h3 id="public-urls-van-mo-adult-images-đuoc-khong" tabindex="-1">Public URLs vẫn mở Adult Images được không? <a class="header-anchor" href="#public-urls-van-mo-adult-images-đuoc-khong" aria-label="Permalink to &quot;Public URLs vẫn mở Adult Images được không?&quot;">​</a></h3><p>Nếu current access mode không cho phép rating đó, normal public URLs sẽ không trả original image.</p><h3 id="random-image-api-co-return-restricted-images-khong" tabindex="-1">Random Image API có return Restricted Images không? <a class="header-anchor" href="#random-image-api-co-return-restricted-images-khong" aria-label="Permalink to &quot;Random Image API có return Restricted Images không?&quot;">​</a></h3><p>Không.</p><p>Random image API filter candidates theo current access mode.</p><h3 id="old-unrated-images-thi-sao" tabindex="-1">Old Unrated Images thì sao? <a class="header-anchor" href="#old-unrated-images-thi-sao" aria-label="Permalink to &quot;Old Unrated Images thì sao?&quot;">​</a></h3><p>Unrated images không bị ẩn tự động chỉ vì chưa có moderation results. Bạn có thể adjust ratings sau trong admin panel.</p>',67)])])}const b=i(o,[["render",h]]);export{p as __pageData,b as default};
